-- ----------------------------
-- Table structure for spc_indicator
-- ----------------------------
DROP TABLE IF EXISTS `spc_indicator`;
CREATE TABLE `spc_indicator`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `job_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '作业id',
  `indicator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '指标名称',
  `class_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '所属科室',
  `system_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '所属系统',
  `indicator_level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '指标级别',
  `point` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '点位(指标ID)',
  `point_unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '点位单位',
  `start_value` decimal(18, 2) NOT NULL COMMENT 'Y轴起始值',
  `step` decimal(18, 2) NOT NULL COMMENT 'y轴步长',
  `target_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '目标值',
  `ucl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '控制线上限值',
  `lcl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '控制线下限值',
  `uwl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '警告线上限值',
  `lwl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '警告线下限值',
  `usl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '规格线上限值',
  `lsl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '规格线下限值',
  `u3l_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '3σ上限值',
  `l3l_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '3σ下限值',
  `uacl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '自控线上限值',
  `lacl_value` decimal(18, 3) NULL DEFAULT NULL COMMENT '自控线下限值',
  `ocap` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '绑定的OCAP流程模版ID',
  `deleted` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否删除',
  `creator` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建者',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `end_value` decimal(18, 2) NULL DEFAULT NULL COMMENT 'Y轴最大值',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_update_time`(`update_time`) USING BTREE,
  INDEX `idx_job_id`(`job_id`) USING BTREE,
  INDEX `idx_point`(`point`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16037 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'SPC指标设定表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of spc_indicator
-- ----------------------------

SET FOREIGN_KEY_CHECKS = 1;
